import { describe, expect, it, beforeEach } from "vitest";
import { addCartItem, clearCart } from "@/lib/db/store";
import { buildCartResponse } from "./cart-response";

const PILOT = "r-pilot-1";

describe("buildCartResponse", () => {
  beforeEach(() => clearCart(PILOT));

  it("returns an empty payload when the cart is empty", () => {
    expect(buildCartResponse(PILOT)).toEqual({ groups: [], grandTotalPaise: 0, itemCount: 0 });
  });

  it("groups items by distributor and computes correct subtotals + grandTotal", () => {
    addCartItem(PILOT, "m-paracetamol-500", 2); // d-mediplus, 22 INR -> 4400 paise
    addCartItem(PILOT, "m-amoxicillin-500", 1); // d-mediplus, 84 INR -> 8400 paise
    addCartItem(PILOT, "m-vitd3-60k", 3); // d-omsai, 31 INR -> 9300 paise
    const r = buildCartResponse(PILOT);
    expect(r.groups).toHaveLength(2);
    const med = r.groups.find((g) => g.distributor.id === "d-mediplus");
    const om = r.groups.find((g) => g.distributor.id === "d-omsai");
    expect(med?.items.length).toBe(2);
    expect(med?.subtotalPaise).toBe(2 * 2200 + 1 * 8400);
    expect(om?.items.length).toBe(1);
    expect(om?.subtotalPaise).toBe(3 * 3100);
    expect(r.grandTotalPaise).toBe((med?.subtotalPaise ?? 0) + (om?.subtotalPaise ?? 0));
    expect(r.itemCount).toBe(2 + 1 + 3);
  });
});

import { describe, expect, it, vi } from "vitest";

let hasCookie = true;
vi.mock("next/headers", () => ({
  cookies: () => ({ get: () => (hasCookie ? { value: "r-pilot-1" } : undefined) }),
}));

import { POST } from "./route";
import { clearCart } from "@/lib/db/store";

describe("POST /api/cart/items", () => {
  beforeEach(() => clearCart("r-pilot-1"));

  it("returns 401 without a session cookie", async () => {
    hasCookie = false;
    const res = await POST(new Request("http://localhost/api/cart/items", { method: "POST", body: "{}" }));
    expect(res.status).toBe(401);
    hasCookie = true;
  });

  it("returns 400 on invalid JSON", async () => {
    const res = await POST(new Request("http://localhost/api/cart/items", { method: "POST", body: "not-json" }));
    expect(res.status).toBe(400);
  });

  it("returns 400 when medicineId is missing", async () => {
    const res = await POST(new Request("http://localhost/api/cart/items", { method: "POST", body: JSON.stringify({}) }));
    expect(res.status).toBe(400);
  });

  it("returns 404 when medicineId is unknown", async () => {
    const res = await POST(new Request("http://localhost/api/cart/items", { method: "POST", body: JSON.stringify({ medicineId: "m-does-not-exist" }) }));
    expect(res.status).toBe(404);
  });

  it("adds the line and returns the cart payload on success", async () => {
    const res = await POST(new Request("http://localhost/api/cart/items", { method: "POST", body: JSON.stringify({ medicineId: "m-paracetamol-500", qty: 2 }) }));
    expect(res.status).toBe(200);
    const body = (await res.json()) as { itemCount: number; grandTotalPaise: number };
    expect(body.itemCount).toBe(2);
    expect(body.grandTotalPaise).toBeGreaterThan(0);
  });
});
